    # Helper to check if a word/phrase looks like a person's name
    def is_name(word):
        # Remove punctuation
        word = word.strip('.,!?;:()[]{}"\'')
        # Split into words (for multi-word names)
        parts = word.split()
        # Name must have at least one part, all starting with uppercase, and not all uppercase (to avoid acronyms)
        if not parts:
            return False
        for part in parts:
            if not part or not part[0].isupper() or not part.isalpha():
                return False
        return True

    # Lowercase for searching, but keep original for extraction
    lowered = text.lower()
    preps = ["about", "on", "of", "from", "next to"]
    idx = -1
    found_prep = ""
    for prep in preps:
        i = lowered.find(prep + " ")
        if i != -1:
            if idx == -1 or i < idx:
                idx = i
                found_prep = prep
    if idx != -1:
        # Find the entity after the preposition
        start = idx + len(found_prep) + 1
        # Take up to next comma, period, or end of string
        end = len(text)
        for sep in [',', '.', ';', ':', '?', '!']:
            sep_idx = text.find(sep, start)
            if sep_idx != -1 and sep_idx < end:
                end = sep_idx
        entity = text[start:end].strip()
        # Take only the first 1 or 2 words (to avoid long phrases)
        entity_words = entity.split()
        if entity_words:
            entity = ' '.join(entity_words[:2])
        return is_name(entity)
    else:
        # No preposition found, try to get main subject (first noun phrase)
        # Assume subject is first 1 or 2 words before a verb or comma
        words = text.strip().split()
        if not words:
            return False
        # Find first verb (very basic: look for 'is', 'was', 'are', 'were', 'has', 'have', 'had', 'does', 'do', 'did', 'will', 'shall', 'can', 'could', 'would', 'should', 'may', 'might', 'must')
        verbs = {'is','was','are','were','has','have','had','does','do','did','will','shall','can','could','would','should','may','might','must'}
        subj = []
        for w in words:
            lw = w.lower().strip('.,!?;:')
            if lw in verbs or w[0].islower():
                break
            subj.append(w)
            if len(subj) == 2:
                break
        if not subj:
            subj = [words[0]]
        subject = ' '.join(subj)
        return is_name(subject)

