    }

    verb_suffixes = ("ed", "es", "ing", "s")
    common_verbs = {
        "is", "am", "are", "was", "were", "be", "been", "being",
        "go", "goes", "went", "gone", "run", "ran", "see", "saw",
        "eat", "ate", "make", "made", "do", "does", "did", "have",
        "has", "had", "get", "got", "take", "took", "come", "came",
        "give", "gave", "find", "found", "put", "say", "said", "sit",
        "sat", "stand", "stood", "walk", "talk", "look", "move", "live",
        "play", "work", "read", "write", "wrote", "fall", "fell"
    }

    words = text.lower().replace(".", " ").replace(",", " ").split()

    verb_index = None
    for i, w in enumerate(words):
        if w in common_verbs or (len(w) > 3 and w.endswith(verb_suffixes)):
            verb_index = i
            break

    if verb_index is None:
        return False

    for j in range(verb_index + 1, len(words)):
        w = words[j]
        if w in prepositions:
            return True
        if w.endswith("ly") and len(w) > 3:
            return True

    return False

def rule(text: str) -> bool:
    extra_adverbs = {
        "again", "everywhere", "today", "overhead", "upstairs",
        "nearby", "outside", "inside", "here", "there", "now",
        "then", "soon", "never", "always", "often", "sometimes",
        "everyday", "yesterday", "tomorrow", "downstairs", "abroad",
        "ahead", "away", "everywhere", "anywhere", "somewhere",
        "indoors", "outdoors", "upward", "downward", "forward",
        "backward", "everywhere",
    }
    non_adverb_ly = {
        "fly", "ally", "rely", "apply", "supply", "reply", "imply",
        "comply", "july", "italy", "family", "only", "holy", "ugly",
        "early", "lily", "rally", "belly", "jelly", "bully", "fully",
        "silly", "really",
    }
    for raw in text.split():
        word = "".join(ch for ch in raw if ch.isalpha()).lower()
        if not word:
            continue
        if word in extra_adverbs:
            return True
        if word.endswith("ly") and len(word) > 3 and word not in non_adverb_ly:
            return True
    return False

def rule(text: str) -> bool:
    lowered = text.lower()

    prepositions = {
        "at", "by", "in", "inside", "on", "under", "over", "above", "below",
        "beneath", "behind", "beside", "near", "across", "around", "through",
        "between", "among", "into", "onto", "upon", "within", "outside",
        "toward", "towards", "against", "off", "down", "up",
    }

    location_words = {
        "home", "downtown", "overhead", "outside", "inside", "upstairs",
        "downstairs", "nearby", "abroad", "indoors", "outdoors", "here",
        "there", "everywhere", "somewhere", "anywhere", "nowhere", "uptown",
        "underground", "offshore", "ashore", "aboard", "north", "south",
        "east", "west", "left", "right", "ahead", "behind", "away",
        "back", "forward", "below", "above",
    }

    # strip punctuation into spaces
    cleaned = "".join(c if c.isalpha() or c == " " else " " for c in lowered)
    words = cleaned.split()

    for w in words:
        if w in location_words:
            return True

    # check for prepositional phrase: preposition followed by a noun-like word
    for i, w in enumerate(words):
        if w in prepositions and i + 1 < len(words):
            nxt = words[i + 1]
            # phrase like "at home", "by the barn", "in the house"
            if nxt in {"the", "a", "an", "this", "that", "my", "your",
                       "his", "her", "their", "our", "some", "his"}:
                if i + 2 < len(words):
                    return True
            else:
                return True

    return False
